static void req(bool b,const std::string&m){if(!b)throw std::runtime_error(m);}SparseMatrixCSC SparseMatrixCSC::from_linear_indices(int r,int c,const std::vector<unsigned long long>&lin,const std::vector<double>&vals){req(lin.size()==vals.size(),"sparse size mismatch");struct E{int c,r;double v;};std::vector<E>e;e.reserve(lin.size());for(size_t k=0;k<lin.size();++k){int rr=(int)(lin[k]%(unsigned long long)r),cc=(int)(lin[k]/(unsigned long long)r);if(vals[k]!=0)e.push_back({cc,rr,vals[k]});}std::sort(e.begin(),e.end(),[](auto&a,auto&b){return a.c==b.c?a.r<b.r:a.c<b.c;});SparseMatrixCSC A(r,c);A.row_idx.resize(e.size());A.values.resize(e.size());for(auto&x:e)++A.col_ptr[(size_t)x.c+1];for(int j=0;j<c;++j)A.col_ptr[j+1]+=A.col_ptr[j];auto cur=A.col_ptr;for(auto&x:e){int p=cur[x.c]++;A.row_idx[p]=x.r;A.values[p]=x.v;}return A;}void SparseMatrixCSC::multiply(const std::vector<double>&x,std::vector<double>&y)const{y.assign(rows,0);for(int j=0;j<cols;++j){double xj=x[j];if(xj)for(int p=col_ptr[j];p<col_ptr[j+1];++p)y[row_idx[p]]+=values[p]*xj;}}void SparseMatrixCSC::transpose_multiply(const std::vector<double>&x,std::vector<double>&y)const{y.assign(cols,0);for(int j=0;j<cols;++j){double s=0;for(int p=col_ptr[j];p<col_ptr[j+1];++p)s+=values[p]*x[row_idx[p]];y[j]=s;}}double SparseMatrixCSC::column_dot(int a,int b)const{int p=col_ptr[a],pe=col_ptr[a+1],q=col_ptr[b],qe=col_ptr[b+1];double s=0;while(p<pe&&q<qe){if(row_idx[p]==row_idx[q]){s+=values[p++]*values[q++];}else if(row_idx[p]<row_idx[q])++p;else ++q;}return s;}Matrix matmul(const Matrix&A,const Matrix&B){req(A.cols==B.rows,"matmul mismatch");Matrix C(A.rows,B.cols);for(int j=0;j<B.cols;++j)for(int k=0;k<A.cols;++k){double b=B(k,j);if(b)for(int i=0;i<A.rows;++i)C(i,j)+=A(i,k)*b;}return C;}Matrix transpose(const Matrix&A){Matrix T(A.cols,A.rows);for(int j=0;j<A.cols;++j)for(int i=0;i<A.rows;++i)T(j,i)=A(i,j);return T;}Matrix add(const Matrix&A,const Matrix&B,double alpha){req(A.rows==B.rows&&A.cols==B.cols,"add mismatch");Matrix C(A.rows,A.cols);for(size_t i=0;i<A.a.size();++i)C.a[i]=A.a[i]+alpha*B.a[i];return C;}Matrix solve_dense(Matrix A,Matrix B,bool chol){req(A.rows==A.cols&&A.rows==B.rows,"solve mismatch");int n=A.rows,nrhs=B.cols,info=0;if(chol){Matrix Ac=A,Bc=B;char u='L';dposv_(&u,&n,&nrhs,Ac.a.data(),&n,Bc.a.data(),&n,&info);if(info==0)return Bc;}std::vector<int>ipiv(n);dgesv_(&n,&nrhs,A.a.data(),&n,ipiv.data(),B.a.data(),&n,&info);if(info)throw std::runtime_error("dgesv failed");return B;}Matrix inverse(Matrix A){return solve_dense(A,Matrix::eye(A.rows),false);}double det3(const Matrix&A){return A(0,0)*(A(1,1)*A(2,2)-A(2,1)*A(1,2))-A(0,1)*(A(1,0)*A(2,2)-A(2,0)*A(1,2))+A(0,2)*(A(1,0)*A(2,1)-A(2,0)*A(1,1));}Matrix orthonormalize3(const Matrix&Ain){int m=3,n=3,info=0,lwork=-1;Matrix A=Ain;std::vector<double>s(3),u(9),vt(9);double wk;char job='A';dgesvd_(&job,&job,&m,&n,A.a.data(),&m,s.data(),u.data(),&m,vt.data(),&n,&wk,&lwork,&info);lwork=std::max(32,(int)wk);std::vector<double>w(lwork);A=Ain;dgesvd_(&job,&job,&m,&n,A.a.data(),&m,s.data(),u.data(),&m,vt.data(),&n,w.data(),&lwork,&info);if(info)throw std::runtime_error("dgesvd failed");Matrix U(3,3),VT(3,3);U.a=std::move(u);VT.a=std::move(vt);Matrix V=transpose(VT),D=Matrix::eye(3);D(2,2)=det3(U)*det3(V)>=0?1:-1;return matmul(matmul(U,D),VT);}Matrix rod2dcm(const std::vector<double>&r){double n=std::sqrt(r[0]*r[0]+r[1]*r[1]+r[2]*r[2]);Matrix R=Matrix::eye(3);if(n==0)return R;double th=2*std::atan(n),sx=r[0]/n,sy=r[1]/n,sz=r[2]/n,c=std::cos(th),s=std::sin(th);R(0,0)=sx*sx+(1-sx*sx)*c;R(0,1)=sx*sy*(1-c)+sz*s;R(0,2)=sx*sz*(1-c)-sy*s;R(1,0)=sx*sy*(1-c)-sz*s;R(1,1)=sy*sy+(1-sy*sy)*c;R(1,2)=sy*sz*(1-c)+sx*s;R(2,0)=sx*sz*(1-c)+sy*s;R(2,1)=sy*sz*(1-c)-sx*s;R(2,2)=sz*sz+(1-sz*sz)*c;return R;}std::vector<double> flatten_col_major(const Matrix&M){return M.a;}Matrix skew(const std::vector<double>&g){Matrix G(3,3);G(0,1)=-g[2];G(0,2)=g[1];G(1,0)=g[2];G(1,2)=-g[0];G(2,0)=-g[1];G(2,1)=g[0];return G;}double frobenius_squared(const Matrix&A){double s=0;for(double v:A.a)s+=v*v;return s;}CMatrix eig_complex(const Matrix&A,std::vector<std::complex<double>>&evals){int n=A.rows,info=0,lda=n,ldvl=1,ldvr=n,lwork=-1;std::vector<std::complex<double>>Ac((size_t)n*n),vl(1),vr((size_t)n*n),workq(1);for(size_t i=0;i<A.a.size();++i)Ac[i]={A.a[i],0};evals.assign(n,{});std::vector<double>rwork(2*(size_t)n);char N='N',V='V';zgeev_(&N,&V,&n,Ac.data(),&lda,evals.data(),vl.data(),&ldvl,vr.data(),&ldvr,workq.data(),&lwork,rwork.data(),&info);lwork=std::max(2*n,(int)std::ceil(workq[0].real()));std::vector<std::complex<double>>work(lwork);for(size_t i=0;i<A.a.size();++i)Ac[i]={A.a[i],0};zgeev_(&N,&V,&n,Ac.data(),&lda,evals.data(),vl.data(),&ldvl,vr.data(),&ldvr,work.data(),&lwork,rwork.data(),&info);if(info)throw std::runtime_error("zgeev failed");CMatrix M(n,n);M.a=std::move(vr);for(int c=0;c<n;++c){auto d=M(0,c);if(std::abs(d)>std::numeric_limits<double>::epsilon())for(int r=0;r<n;++r)M(r,c)/=d;}return M;}
